    def pdf(self, x):
        b, n, mu = self.b, self.n, self.mu
        dividend = b**n*(x - mu)**(-1-n)
        divisor = (exp(b/(x-mu))-1)*(gamma(n)*zeta(n))
        return dividend/divisor


